// Push notification handler for SOWKNOW PWA
// Imported by the main service worker generated by next-pwa

self.addEventListener('push', function(event) {
  var data = {};
  try {
    data = event.data ? event.data.json() : {};
  } catch (e) {
    data = { title: 'SOWKNOW', body: event.data ? event.data.text() : '' };
  }

  var title = data.title || 'SOWKNOW';
  var options = {
    body: data.body || 'You have a notification',
    icon: '/icons/icon-192x192.png',
    badge: '/icons/icon-72x72.png',
    tag: data.data && data.data.tag ? data.data.tag : 'sowknow-default',
    requireInteraction: true,
    data: data.data || {}
  };

  event.waitUntil(
    self.registration.showNotification(title, options)
  );
});

self.addEventListener('notificationclick', function(event) {
  event.notification.close();
  var notificationData = event.notification.data || {};
  var targetUrl = notificationData.taskId ? '/tasks/' + notificationData.taskId : '/tasks';

  event.waitUntil(
    self.clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function(clientList) {
      for (var i = 0; i < clientList.length; i++) {
        var client = clientList[i];
        if (client.url.indexOf(targetUrl) !== -1 && 'focus' in client) {
          return client.focus();
        }
      }
      if (self.clients.openWindow) {
        return self.clients.openWindow(targetUrl);
      }
    })
  );
});
